select count(*) from postgres.votes as v, postgres.posts as p, postgres.badges as b, postgres.users as u where u.id = v.userid and u.id = p.owneruserid and u.id = b.userid and v.creationdate<=timestamp '2014-09-06 00:00:00' and p.score<=48 and p.answercount<=8 and b."date">=timestamp '2011-01-03 20:50:19' and b."date"<=timestamp '2014-09-02 15:35:07' and u.creationdate>=timestamp '2010-11-16 06:03:04';
